  chatbot_c_label: { en: "Instant Answers", fr: "R\u00e9ponses imm\u00e9diates", de: "Sofortige Antworten", es: "Respuestas instant\u00e1neas" },
  chatbot_c_title: { en: "Ask Stratifit <span>AI</span>", fr: "Demandez \u00e0 Stratifit <span>IA</span>", de: "Fragen Sie Stratifit <span>KI</span>", es: "Preg\u00fantale a Stratifit <span>IA</span>" },
  chatbot_c_subtitle: { en: "Get instant answers about pricing, timelines, and more. Or talk to a human \u2014 your choice.", fr: "Obtenez des r\u00e9ponses imm\u00e9diates sur les tarifs, les d\u00e9lais, et plus encore. Ou parlez \u00e0 un humain \u2014 vous choisissez.", de: "Erhalten Sie sofort Antworten zu Preisen, Zeitpl\u00e4nen und mehr. Oder sprechen Sie mit einem Menschen \u2014 Sie haben die Wahl.", es: "Obt\u00e9n respuestas instant\u00e1neas sobre precios, plazos y m\u00e1s. O habla con un humano \u2014 t\u00fa decides." },
  chatbot_c_placeholder: { en: "Ask about pricing, timeline, tech stack\u2026", fr: "Posez vos questions\u00a0: tarifs, d\u00e9lais, stack technique\u2026", de: "Fragen zu Preisen, Zeitplan, Tech-Stack\u2026", es: "Pregunta sobre precios, plazos, stack\u2026" },
