  chatbot_cs_header_subtitle: { en: "Online \u00b7 Pre-launch concierge", fr: "En ligne \u00b7 Conciergerie pr\u00e9-lancement", de: "Online \u00b7 Pre-Launch-Concierge", es: "En l\u00ednea \u00b7 Conserje de pre-lanzamiento" },
