  chatbot_f_show_all: { en: "Show all", fr: "Tout afficher", de: "Alle anzeigen", es: "Mostrar todo" },
  chatbot_f_fallback: { en: "\ud83e\udd14 I couldn\u2019t find a matching answer. Try a popular question above, or tap below to chat with a human \u2014 we typically reply within 24 hours.", fr: "\ud83e\udd14 Je n\u2019ai pas trouv\u00e9 de r\u00e9ponse. Essayez une question populaire ci-dessus, ou cliquez ci-dessous pour parler \u00e0 un humain \u2014 nous r\u00e9pondons g\u00e9n\u00e9ralement sous 24\u00a0heures.", de: "\ud83e\udd14 Ich habe keine passende Antwort gefunden. Probieren Sie eine beliebte Frage oben oder klicken Sie unten, um mit einem Menschen zu sprechen \u2014 wir antworten in der Regel innerhalb von 24 Stunden.", es: "\ud83e\udd14 No encontr\u00e9 una respuesta. Prueba con una pregunta popular arriba o toca abajo para hablar con un humano \u2014 solemos responder en 24 horas." },
  chatbot_f_human_cta: { en: "Talk to a human", fr: "Parler \u00e0 un humain", de: "Mit einem Menschen sprechen", es: "Hablar con un humano" },
  chatbot_f_footer_human: { en: "Prefer a human? We\u2019ll reply within 24h.", fr: "Pr\u00e9f\u00e9rez un humain\u00a0? Nous r\u00e9pondons sous 24\u00a0h.", de: "Lieber mit einem Menschen sprechen? Wir antworten innerhalb von 24\u00a0h.", es: "\u00bfPrefieres un humano? Respondemos en 24\u00a0h." },
  chatbot_f_footer_cta: { en: "Contact Team", fr: "Contacter l\u2019\u00e9quipe", de: "Team kontaktieren", es: "Contactar al equipo" },
  chatbot_f_human_opening: { en: "Opening the contact form so a human can take over\u2026", fr: "J\u2019ouvre le formulaire pour qu\u2019un humain prenne le relais\u2026", de: "\u00d6ffne das Kontaktformular, damit ein Mensch \u00fcbernehmen kann\u2026", es: "Abriendo el formulario para que un humano tome el relevo\u2026" },
