  chatbot_f_no_popular: { en: "No popular questions in {topic} yet \u2014 tap Show all or type your question below.", fr: "Pas encore de questions populaires dans {topic}\u00a0 \u2014 cliquez sur Tout afficher ou tapez votre question ci-dessous.", de: "Noch keine beliebten Fragen in {topic} \u2014 klicken Sie auf Alle anzeigen oder geben Sie unten Ihre Frage ein.", es: "A\u00fan no hay preguntas populares en {topic} \u2014 toca Mostrar todo o escribe tu pregunta abajo." },
